DELETE FROM posts WHERE organization_id = 'ea096f77-9616-40ec-95d7-2f32f250b93a' AND scheduled_at >= '2026-07-01' AND scheduled_at < '2026-08-01';

INSERT INTO posts (organization_id, title, scheduled_at, format, pillar, copy, caption, plate, in_drive, published, created_by, status)
SELECT
  'ea096f77-9616-40ec-95d7-2f32f250b93a'::uuid,
  elem->>'title',
  (elem->>'scheduled_at')::timestamptz,
  (elem->>'format')::post_format,
  NULLIF(elem->>'pillar', ''),
  NULLIF(elem->>'copy', ''),
  NULLIF(elem->>'caption', ''),
  NULLIF(elem->>'plate', ''),
  COALESCE((elem->>'in_drive')::boolean, false),
  false,
  'f662b9e4-8fae-4649-9624-4c4c872f46e0'::uuid,
  'draft'::post_status
FROM jsonb_array_elements($j$[{"title": "WHERE OPERATIONS BEGIN.", "scheduled_at": "2026-07-01", "pillar": "Valor", "format": "image", "copy": "Título: WHERE OPERATIONS BEGIN.\n\nSubtítulo: Before the first drill turns, the right fleet has to be in place.", "caption": "Every project in the oil and energy sector starts with a logistical decision — and that decision determines everything that follows.\n\nThe right units, in the right condition, deployed at the right moment. That’s not luck. That’s PetroEquip.\n\nFollow us to see the fleet that keeps the industry moving.\n\n#PetroEquip #OilAndGas #IndustrialLogistics #OperationalStart #FleetDeployment #EnergySector #StrategicLogistics", "plate": null, "in_drive": true}, {"title": "ELEVATED ACCESS.", "scheduled_at": "2026-07-03", "pillar": "Ventas", "format": "carousel", "copy": "Slide 1: ELEVATED ACCESS.\n\nBuilt for operations that reach higher.\n\nSlide 2: Ford F-800D — Bucket Truck \nPickman hydraulic arm · Aerial access · Electrical and structural field work\n\nSlide 3: When ground level isn’t enough, this unit gets your team where the work is.\n\nSlide 4 (CTA): Available for your project. \n Contact us to coordinate.", "caption": "Aerial access operations demand precision equipment and zero margin for error.\n\nThe Ford F-800D bucket truck with Pickman arm delivers safe, stable elevated access for electrical infrastructure, structural inspection, and field maintenance in oil and energy environments.\n\nA unit built for the work that can’t wait.\n\nDM us to check availability and coordinate deployment.\n#PetroEquip #BucketTruck #AerialAccess #PickmanArm #OilAndGas #ElectricalInfrastructure #FieldOperations #IndustrialEquipment", "plate": "73UCAA", "in_drive": true}, {"title": "(Motion intro):", "scheduled_at": "2026-07-05", "pillar": "Información", "format": "video_carousel", "copy": "Slide 1 (Motion intro): \n\n50+ YEARS OF FLEET. \n\nFrom proven iron to modern engineering.\n\nSlide 2 (Unidades animadas — cronológico): \n\n1971 · 1983 · 2008 · 2025 \n\nFour decades of operational capacity — all active, all maintained, all ready.\n\nSlide 3: \n\nExperience isn’t just about age. \n\nIt’s about knowing which unit each operation demands — and having it ready.\n\nSlide 4 (CTA — animated end card): \n\nOld iron. New standards. \n\nOne fleet.", "caption": "The PetroEquip fleet spans more than five decades of operational history — and every single unit is active.\n\nFrom the Chevrolet C-60 (1971) and the Chevrolet Platform (1983) to the Freightliner (2008) and the ZXAuto Terralord (2025), our fleet combines field-proven durability with modern engineering. Different eras. Same standard of maintenance, supervision, and deployment readiness.\n\nBecause experience isn’t a year on a title — it’s a unit that shows up ready every time.\nSee the full fleet at www.petroequip.com.ve\n\n#PetroEquip #FleetHistory #OldIronNewStandards #OilAndGas #IndustrialFleet #SpecializedEquipment #FleetEvolution #EnergySector", "plate": "A07AB3P (1971) / A11CH7M (1983) / A34BK0R (2008) / A89EN4P (2025)", "in_drive": false}, {"title": "BUILT FOR THE FIELD.", "scheduled_at": "2026-07-07", "pillar": "Ventas", "format": "image", "copy": "Título: BUILT FOR THE FIELD.\n\nSubtítulo: ZXAuto Terralord 2024 — 4x4 double cab, operational-grade.", "caption": "Remote terrain, active field operations, daily technical logistics — the ZXAuto Terralord 2024 handles all three without compromising performance.\n\nA 4x4 double cab unit that combines modern engineering with the durability oil and energy projects demand, day in and day out.\n\nReady to deploy. Available now.\n\nSend us a message to integrate it into your operation.\n#PetroEquip #ZXAutoTerralord #4x4 #DoubleCAb #FieldMobility #OilAndGas #IndustrialPickup #FleetAvailability", "plate": "A54EW9A", "in_drive": true}, {"title": "ADAPTABILITY IS NOT A FEATURE.", "scheduled_at": "2026-07-09", "pillar": "Valor", "format": "carousel", "copy": "Slide 1: ADAPTABILITY IS NOT A FEATURE.\n \nIt’s how we operate.\n\nSlide 2: Every project has different terrain, timelines, and technical demands. \n\nWe don’t offer a fixed solution — we build the right one.\n\nSlide 3: Ambulances for HSE coverage · Cranes for heavy lifts · 4x4s for remote access · Welding units for on-site intervention\n\nSlide 4 (CTA): Whatever your operation requires. \n\nPetroEquip has it ready.", "caption": "No two oil or energy projects are identical — and a logistics partner that treats them like they are will always fall short.\n\nAt PetroEquip we adapt our fleet deployment to the specific technical, geographic, and operational demands of each contract. Light units, heavy equipment, emergency coverage — structured around what your project actually needs.\n\nFlexibility without compromising standards.\n\nTell us about your operation — let’s build the right solution together.\n\n#PetroEquip #Adaptability #SpecializedFleet #OilAndGas #IndustrialSolutions #FleetManagement #CustomLogistics #EnergySector", "plate": null, "in_drive": false}, {"title": "THREE BRANDS. ONE MISSION.", "scheduled_at": "2026-07-11", "pillar": "Información", "format": "image", "copy": "Título: THREE BRANDS. ONE MISSION.\n\nSubtítulo: Modern pickup fleet for field operations that don’t stop.\n\nCuerpo: Dongfeng · Dongfeng · Great Wall — reliable, modern, operational.", "caption": "Modern doesn’t just mean new — it means engineered for what the field actually demands.\n\nThe Dongfeng 2021, Dongfeng 2022, and Great Wall Wingle 2024 represent three of the most versatile pickup units in the PetroEquip fleet. Different brands, same standard: daily field reliability for personnel transport, technical supervision, and operational coordination in oil and energy projects.\n\nThree units. Zero excuses. Save this post and contact us when your project needs field mobility.\n\n#PetroEquip #Dongfeng #GreatWall #FieldPickup #ModernFleet #OilAndGas #PickupFleet #IndustrialMobility", "plate": "A72DR7V / A75DR7V / A45EW4P", "in_drive": false}, {"title": "(Motion opener): THREE AMBULANCES.", "scheduled_at": "2026-07-13", "pillar": "Ventas", "format": "video_carousel", "copy": "Slide 1 (Motion opener): THREE AMBULANCES. \n\nOne standard of emergency coverage.\n\nSlide 2 (Units animated in): Chevrolet 2012 · Chevrolet 2013 · Iveco 2012 \n\nThree emergency response units integrated into industrial field operations.\n\nSlide 3: HSE compliance · On-site medical response · Immediate deployment \n\nBecause industrial safety is non-negotiable.\n\nSlide 4 (CTA): Add emergency coverage to your project. \n\nContact PetroEquip today.", "caption": "Industrial safety doesn’t end with equipment inspections and protocol checklists — it requires having medical response capability directly on-site.\n\nPetroEquip operates three ambulance units available for oil, energy, and industrial field operations: Chevrolet 2012, Chevrolet 2013, and Iveco 2012. Each unit ready for immediate deployment and integrated HSE coverage.\n\nBecause the operation that protects its people is the one built to last.\n\nLearn more at www.petroequip.com.ve\n\n#PetroEquip #HSE #Ambulance #EmergencyResponse #FieldSafety #OilAndGas #IndustrialSafety #MedicalCoverage", "plate": "A12AT1A / A46BE6A / A12CB7G", "in_drive": false}, {"title": "THE FLEET BEHIND THE PROJECT.", "scheduled_at": "2026-07-15", "pillar": "Valor", "format": "carousel", "copy": "Slide 1: THE FLEET BEHIND THE PROJECT.\n\nWhat industrial clients actually need from a logistics partner.\n\nSlide 2: Not just units on paper. \n\nMaintained equipment, technically supervised, and deployable within your timeline.\n\nSlide 3: Not just availability. \nA partner that understands what each phase of your operation demands — and prepares for it in advance.\n\nSlide 4 (CTA): That 's the PetroEquip standard. \n\nDM us to start the conversation.", "caption": "A logistics provider gives you a vehicle. A logistics partner gives you operational certainty.\n\nAt PetroEquip the difference is built into everything we do — from the preventive maintenance schedule to the deployment coordination and field technical support. We don’t react to your project. We prepare for it.\n\nBecause in oil and energy operations, preparation is the service.\n\nContact  us and let’s talk about what your next project needs.\n\n#PetroEquip #LogisticsPartner #OilAndGas #IndustrialOperations #FleetManagement #OperationalCertainty #EnergyIndustry", "plate": null, "in_drive": false}, {"title": "DAILY FIELD PERFORMANCE.", "scheduled_at": "2026-07-17", "pillar": "Ventas", "format": "image", "copy": "Título: DAILY FIELD PERFORMANCE.\n\nSubtítulo: ZXAuto 2024 double cab — consistent, capable, available.", "caption": "Daily field logistics requires a vehicle that shows up ready — every single day.\n\nThe ZXAuto 2024 double cab delivers exactly that: consistent performance for personnel transport, on-site coordination, and daily operational support across active oil and energy projects.\n\nNo surprises. No delays. Just execution.\n\nFollow us and reach out when you need field mobility that doesn’t fail.\n\n#PetroEquip #ZXAuto #4x4Pickup #FieldLogistics #DailyOperations #OilAndGas #IndustrialMobility #OperationalFleet", "plate": "A51EW4A", "in_drive": false}, {"title": "TWO WELDING UNITS.", "scheduled_at": "2026-07-19", "pillar": "Información", "format": "carousel", "copy": "Slide 1: TWO WELDING UNITS.\n\nField intervention without the wait.\n\nSlide 2: Toyota Dyna 1999 · Chevrolet 2012 \n\nTwo fully equipped industrial welding units ready for on-site corrective and preventive work.\n\nSlide 3: Structural repairs · On-site intervention · Zero equipment transfer \n\nLess downtime. More continuity.\n\nSlide 4 (CTA): Integrate a welding unit into your project. \n\nContact us directly.", "caption": "When a structural repair is needed in the field, the clock starts immediately — and every hour of transfer time is an hour of lost production.\n\nPetroEquip operates two industrial welding units — Toyota Dyna 1999 and Chevrolet 2012 — fully equipped for on-site intervention in oil, energy, and industrial environments. Corrective work executed where the problem is, not where the shop is.\n\nTwo units. One purpose: keeping your operation continuous.\n\nContact us directly to coordinate deployment.\n\n#PetroEquip #WeldingUnit #OnSiteWelding #ToyotaDyna #IndustrialMaintenance #OilAndGas #FieldIntervention #OperationalContinuity", "plate": "A28AK1C / A76AS4V", "in_drive": false}, {"title": "(Motion opener): PLATFORM OPERATIONS.", "scheduled_at": "2026-07-21", "pillar": "Ventas", "format": "video_carousel", "copy": "Slide 1 (Motion opener): PLATFORM OPERATIONS. \n\nHeavy loads moved with precision.\n\nSlide 2 (Units animated): Chevrolet C-60 1971 — Hydraulic platform arm\n\nChevrolet Platform 1983 — Industrial structural transport\n\nSlide 3: Structural mobilization · Heavy load transport · Field infrastructure support \n\nTwo units. Double the operational capacity.\n\nSlide 4 (CTA): Ready for your project. \n\nCheck availability now.", "caption": "Platform operations in the oil and energy sector require more than just carrying capacity — they require structural stability, operational precision, and equipment that doesn’t fail mid-project.\n\nThe Chevrolet C-60 with hydraulic arm and the Chevrolet Platform 1983 bring combined capacity for heavy load transport and structural field mobilization across demanding industrial environments.\n\nTwo platforms. Built for the work that matters.\n\nCheck availability at www.petroequip.com.ve\n\n#PetroEquip #PlatformTruck #HeavyTransport #ChevroletC60 #StructuralOperations #OilAndGas #IndustrialLogistics #FieldEquipment", "plate": "A07AB3P / A11CH7M", "in_drive": false}, {"title": "INTEGRITY IN EVERY CONTRACT.", "scheduled_at": "2026-07-23", "pillar": "Valor", "format": "image", "copy": "Título: INTEGRITY IN EVERY CONTRACT.\n\nSubtítulo: Ethics, transparency, and operational responsibility — built into everything we do.", "caption": "Long-term partnerships in the oil and energy sector aren’t built on price alone — they’re built on trust.\n\nAt PetroEquip every contract, every deployment, and every client interaction is guided by the same principles: integrity, transparency, and logistical responsibility. We don’t cut corners because we understand that our performance directly impacts our clients’ business continuity.\n\nThat’s not a value on a wall. It’s how we operate.\n\nReach out and start building a partnership built on standards.\n\n#PetroEquip #IntegrityFirst #TrustedPartner #OilAndGas #IndustrialStandards #LogisticalResponsibility #CorporateEthics #EnergySector", "plate": null, "in_drive": false}, {"title": "LIGHT UNITS.", "scheduled_at": "2026-07-26", "pillar": "Información", "format": "carousel", "copy": "Slide 1: LIGHT UNITS.\n\nBig operational impact.\n\nSlide 2: Jeep Grand Cherokee 2013 · Chevrolet Pick-Up 2011\n\nAgile, reliable units for supervision, inspection, and rapid on-site coordination.\n\nSlide 3: Not every task needs a heavy unit. \n\nThese two keep your team moving efficiently across active operational sites.\n\nSlide 4 (CTA): Light fleet available for immediate deployment. \n\nContact us.", "caption": "Heavy equipment gets the attention — but light operational units are what keep the daily flow of a project running smoothly.\n\nThe Jeep Grand Cherokee 2013 and Chevrolet Pick-Up 2011 handle the rapid-response side of field operations: site inspections, technical supervision, inter-site coordination, and fast logistics within active project areas.\n\nSmall units. Essential function.\n\nSave this post — contact us when you need agile field mobility.\n\n#PetroEquip #LightFleet #JeepGrandCherokee #ChevroletPickup #FieldSupervision #OilAndGas #OperationalAgility #IndustrialMobility", "plate": "AC636BR / A09BC6A", "in_drive": false}, {"title": "HYDRAULIC REACH.", "scheduled_at": "2026-07-28", "pillar": "Ventas", "format": "image", "copy": "Título: HYDRAULIC REACH.\n\nSubtítulo: Chevrolet 1989 — hydraulic Pickman arm, operational and ready.", "caption": "Field operations that require elevated hydraulic intervention need equipment that’s built for repeated, demanding use — not occasional deployment.\n\nThe Chevrolet 1989 with Pickman hydraulic arm is a proven operational unit for electrical infrastructure work, elevated structural access, and industrial field interventions where reach and stability define the outcome.\n\nOperational. Available. Ready to deploy.\n\nMessage us to coordinate this unit for your project.\n\n#PetroEquip #HydraulicArm #PickmanArm #Chevrolet1989 #ElevatedAccess #OilAndGas #ElectricalInfrastructure #FieldOperations", "plate": "421XGN", "in_drive": false}, {"title": "WE DON’T JUST LEASE EQUIPMENT. We carry the weight of your operation.", "scheduled_at": "2026-07-30", "pillar": "Valor", "format": "carousel", "copy": "Slide 1: WE DON’T JUST LEASE EQUIPMENT. We carry the weight of your operation.\n\nSlide 2: Our mission is to provide integrated mobility solutions that guarantee continuous operation in the most demanding industrial environments.\n\nSlide 3: Our vision is to be the leading strategic ally \n\nIn specialized fleet management — nationally and internationally.\n\nSlide 4 (CTA): This is what drives every unit we deploy. \n\nPetroEquip — solutions in motion for industries that never stop.", "caption": "Behind every unit we deploy is a clear purpose: to be the logistical backbone that allows oil, energy, and industrial operations to run without interruption.\n\nOur mission isn’t just to provide vehicles — it’s to provide operational certainty. Our vision isn’t just growth — it’s to become the most trusted name in specialized fleet management in the most demanding sectors of the industry.\n\nEvery contract we take on is a commitment to that standard.\n\nIf that’s the kind of partner your operation needs, contact us.\n\n#PetroEquip #MissionDriven #IndustrialLogistics #OilAndGas #StrategicPartner #SpecializedFleet #OperationalCertainty #SolutionsInMotion", "plate": null, "in_drive": false}]$j$::jsonb) AS elem;
